class SegmentTree:
    def __init__(self, arr):
        self.n = len(arr)
        self.tree = [0] * (4 * self.n)
        self._build(arr, 0, 0, self.n - 1)

    def _build(self, arr, tree_idx, low, high):
        if low == high:
            self.tree[tree_idx] = arr[low]
            return

        mid = (low + high) // 2
        self._build(arr, 2 * tree_idx + 1, low, mid)
        self._build(arr, 2 * tree_idx + 2, mid + 1, high)
        self.tree[tree_idx] = self.tree[2 * tree_idx + 1] + self.tree[2 * tree_idx + 2]

    def update(self, index, value):
        self._update(0, 0, self.n - 1, index, value)

    def _update(self, tree_idx, low, high, index, value):
        if low == high:
            self.tree[tree_idx] = value
            return

        mid = (low + high) // 2
        if index <= mid:
            self._update(2 * tree_idx + 1, low, mid, index, value)
        else:
            self._update(2 * tree_idx + 2, mid + 1, high, index, value)
        self.tree[tree_idx] = self.tree[2 * tree_idx + 1] + self.tree[2 * tree_idx + 2]

    def query(self, query_low, query_high):
        return self._query(0, 0, self.n - 1, query_low, query_high)

    def _query(self, tree_idx, low, high, query_low, query_high):
        # No overlap
        if high < query_low or low > query_high:
            return 0

        # Complete overlap
        if query_low <= low and high <= query_high:
            return self.tree[tree_idx]

        # Partial overlap
        mid = (low + high) // 2
        left_sum = self._query(2 * tree_idx + 1, low, mid, query_low, query_high)
        right_sum = self._query(2 * tree_idx + 2, mid + 1, high, query_low, query_high)
        return left_sum + right_sum
